function getText(language, scope, key, fallback) {
  const localized = TEXTS[language]?.[scope]?.[key];
  if (localized != null && localized !== "") return localized;
  if (language === "fr") {
    return TEXTS.fr?.[scope]?.[key] || TEXTS.universal?.[scope]?.[key] || fallback;
  }
  const enVal = TEXTS.en?.[scope]?.[key];
  if (enVal != null && enVal !== "") return enVal;
  return fallback;
}

function getQuizQuestionText(language, questionId) {
  const q = TEXTS[language]?.quiz?.questions?.[questionId];
  if (q) return q;
  if (language === "fr") {
    return TEXTS.fr?.quiz?.questions?.[questionId] || TEXTS.universal?.quiz?.questions?.[questionId] || null;
  }
  return TEXTS.en?.quiz?.questions?.[questionId] || null;
}

function getQuizChoiceText(language, questionId, choiceValue, fallback = {}) {
  const pick = (bundle) => bundle?.quiz?.choices?.[questionId]?.[choiceValue];
  return (
    pick(TEXTS[language]) ||
    (language === "fr" ? pick(TEXTS.fr) || pick(TEXTS.universal) : pick(TEXTS.en)) ||
    fallback
  );
}

function useUiPreferences() {
  return reactExports.useSyncExternalStore(subscribeUiPreferences, getUiSnapshot, getUiSnapshot);
}

function subscribeToLanguage(callback) {
  return subscribeUiPreferences(callback);
}

function useTranslation() {
  const { language } = reactExports.useSyncExternalStore(subscribeToLanguage, getUiSnapshot, getUiSnapshot);
  
  const t = (scope, key, fallback) => getText(language, scope, key, fallback);
  
  return { language, t };
}

