const PREFIX = "moovup_quiz_draft_v1";
const MAX_AGE_MS = 14 * 24 * 60 * 60 * 1000;

function draftKey() {
  const s = getSession();
  const id = (s?.email || s?.pseudo || "session").trim() || "session";
  return `${PREFIX}_${id}`;
}

function loadQuizDraft() {
  try {
    const raw = localStorage.getItem(draftKey());
    if (!raw) return null;
    const data = JSON.parse(raw);
    if (!data || typeof data !== "object") return null;
    if (typeof data.savedAt === "number" && Date.now() - data.savedAt > MAX_AGE_MS) {
      localStorage.removeItem(draftKey());
      return null;
    }
    return data;
  } catch {
    return null;
  }
}

/** @param {{ answers: Record<string, string>, stepIndex: number, phase: string }} payload */
function saveQuizDraft(payload) {
  try {
    localStorage.setItem(
      draftKey(),
      JSON.stringify({
        ...payload,
        savedAt: Date.now(),
      }),
    );
  } catch {
    /* quota / private mode */
  }
}

function clearQuizDraft() {
  try {
    localStorage.removeItem(draftKey());
  } catch {
    /* ignore */
  }
}

const KEY = "moovup_last_conversation_id";

function setLastConversationId(id) {
  try {
    if (id == null || Number.isNaN(Number(id))) return;
    localStorage.setItem(KEY, String(id));
  } catch {
    /* ignore */
  }
}

function getLastConversationId() {
  try {
    const v = localStorage.getItem(KEY);
    if (!v) return null;
    const n = Number(v);
    return Number.isFinite(n) && n > 0 ? n : null;
  } catch {
    return null;
  }
}

/** Petit « tick » de validation (Web Audio, aucun fichier externe). */

let sharedCtx = null;

function getAudioContext() {
  const AC = typeof window !== "undefined" && (window.AudioContext || window.webkitAudioContext);
  if (!AC) return null;
  if (!sharedCtx) sharedCtx = new AC();
  return sharedCtx;
}

function beep(ctx, startTime) {
  const t0 = startTime;
  const osc = ctx.createOscillator();
  const gain = ctx.createGain();
  osc.type = "sine";
  osc.frequency.setValueAtTime(920, t0);
  osc.frequency.exponentialRampToValueAtTime(520, t0 + 0.07);
  gain.gain.setValueAtTime(0.0001, t0);
  gain.gain.exponentialRampToValueAtTime(0.07, t0 + 0.012);
  gain.gain.exponentialRampToValueAtTime(0.0001, t0 + 0.11);
  osc.connect(gain);
  gain.connect(ctx.destination);
  osc.start(t0);
  osc.stop(t0 + 0.12);
}

/**
 * Joue un court signal agréable. Ignore silencieusement si l’API audio est indisponible.
 */
function playQuizTickSound() {
  try {
    const ctx = getAudioContext();
    if (!ctx) return;

    const run = () => {
      const t = ctx.currentTime;
      beep(ctx, t);
    };

    if (ctx.state === "suspended") {
      void ctx.resume().then(run);
    } else {
      run();
    }
  } catch {
    /* navigateurs restreints, autoplay policies, etc. */
  }
}

